import base64

from fastapi import FastAPI, HTTPException
from fastapi.responses import Response

app = FastAPI(title="YaChat Icon API", version="1.0.0")

_SHORTCUT_180 = ""


@app.get("/api/icon")
def get_icon(variant: str = "shortcut", size: int = 180):
    if variant.strip().lower() != "shortcut" or int(size) != 180:
        raise HTTPException(status_code=404, detail="Icon variant or size is unavailable.")

    return Response(
        content=base64.b64decode(_SHORTCUT_180),
        media_type="image/png",
        headers={
            "Cache-Control": "public, max-age=31536000, immutable",
            "ETag": '"yachat-shortcut-v4-180"',
            "X-Content-Type-Options": "nosniff",
        },
    )
